 34→/** Check if a task has been cancelled */
 35→async function isTaskCancelled(
 36→  config: SwarmHooksConfig,
 37→): Promise<{ cancelled: boolean; reason?: string }> {
 38→  try {
 39→    const resp = await fetch(
 40→      `${config.apiUrl}/cancelled-tasks?taskId=${encodeURIComponent(config.taskId)}`,
 41→      { method: "GET", headers: apiHeaders(config) },
 42→    );
 43→    if (!resp.ok) return { cancelled: false };
 44→    const data = (await resp.json()) as {
 45→      cancelled?: Array<{ id: string; failureReason?: string }>;
 46→    };
