196→        agentId: config.agentId,
197→        content: fileContent,
198→        name: fileName.replace(/\.\w+$/, ""),
199→        scope: isShared ? "swarm" : "agent",
200→        source: "file_index",
201→        sourcePath: editedPath,
202→      }),
203→    });
204→  } catch {
205→    /* non-blocking */
206→  }
207→}
208→
209→/** Fetch concurrent context for lead agents */
210→async function fetchConcurrentContext(config: SwarmHooksConfig): Promise<string | null> {
211→  try {
212→    const resp = await fetch(`${config.apiUrl}/api/concurrent-context`, {
213→      method: "GET",
214→      headers: apiHeaders(config),
215→    });
216→    if (!resp.ok) return null;
217→
218→    const data = (await resp.json()) as {
219→      processingInboxMessages: Array<{ content: string; source: string; createdAt: string }>;
220→      recentTaskDelegations: Array<{
221→        task: string;
222→        agentName: string | null;
223→        status: string;
224→      }>;
225→      activeSwarmTasks: Array<{
226→        task: string;
227→        agentName: string | null;
228→        status: string;
229→      }>;
230→    };
231→
232→    const lines: string[] = [];
233→
234→    if (data.processingInboxMessages.length > 0) {
235→      lines.push("=== CONCURRENT SESSION AWARENESS ===");
236→      lines.push("");
237→      lines.push("**Other sessions are currently processing these inbox messages:**");
238→      for (const msg of data.processingInboxMessages) {
239→        const preview = msg.content.length > 120 ? `${msg.content.slice(0, 120)}...` : msg.content;
240→        lines.push(`- [${msg.source}] "${preview}" (received ${msg.createdAt})`);
241→      }
242→    }
243→
244→    if (data.recentTaskDelegations.length > 0) {
245→      if (lines.length === 0) lines.push("=== CONCURRENT SESSION AWARENESS ===");
246→      lines.push("");
247→      lines.push("**Recent task delegations (last 5 min):**");
248→      for (const task of data.recentTaskDelegations) {
249→        const preview = task.task.length > 120 ? `${task.task.slice(0, 120)}...` : task.task;
250→        lines.push(`- "${preview}" → ${task.agentName ?? "unassigned"} [${task.status}]`);
251→      }
252→    }
253→
254→    if (data.activeSwarmTasks.length > 0) {
255→      if (lines.length === 0) lines.push("=== CONCURRENT SESSION AWARENESS ===");
256→      lines.push("");
257→      lines.push("**Currently active tasks across the swarm:**");
258→      for (const task of data.activeSwarmTasks) {
259→        const preview = task.task.length > 100 ? `${task.task.slice(0, 100)}...` : task.task;
260→        lines.push(`- ${task.agentName ?? "unassigned"}: "${preview}" [${task.status}]`);
261→      }
262→    }
263→
264→    if (lines.length > 0) {
265→      lines.push("");
266→      lines.push(
267→        "IMPORTANT: Avoid duplicating work that is already being handled by other sessions or agents.",
268→      );
269→      lines.push("=== END CONCURRENT SESSION AWARENESS ===");
270→      return lines.join("\n");
271→    }
272→
273→    return null;
274→  } catch {
275→    return null;
276→  }
277→}
278→
279→/** Run session summarization via Claude Haiku on shutdown */
280→async function summarizeSession(
281→  config: SwarmHooksConfig,
282→  sessionFile: string | undefined,
283→): Promise<void> {
284→  if (!sessionFile) return;
285→
286→  try {
287→    let transcript = "";
288→    try {
289→      const fullTranscript = await Bun.file(sessionFile).text();
290→      transcript = fullTranscript.length > 20000 ? fullTranscript.slice(-20000) : fullTranscript;
291→    } catch {
292→      return;
293→    }
294→
295→    if (transcript.length <= 100) return;
296→
297→    let taskContext = "";
298→    try {
299→      const taskDetails = await fetchTaskDetails(config);
300→      if (taskDetails) {
301→        taskContext = `Task: ${taskDetails.task}`;
302→      }
303→    } catch {
304→      /* no task context */
305→    }
306→
307→    const summarizePrompt = `You are summarizing an AI agent's work session. Extract ONLY high-value learnings.
308→
309→DO NOT include:
310→- Generic descriptions of what was done ("worked on task X")
311→- Tool calls or file reads
312→- Routine progress updates
313→
314→DO include (if present):
315→- **Mistakes made and corrections** — what went wrong and what fixed it
316→- **Discovered patterns** — reusable approaches, APIs, or codebase conventions
317→- **Codebase knowledge** — important file paths, architecture decisions, gotchas
318→- **Environment knowledge** — service URLs, config details, tool quirks
319→- **Failed approaches** — what was tried and didn't work (and why)
320→
321→Format as a bulleted list of concrete, reusable facts. If the session was routine with no significant learnings, respond with exactly: "No significant learnings."
322→${taskContext ? `\nTask context: ${taskContext}` : ""}
323→Transcript:
324→${transcript}`;
325→
326→    const tmpFile = `/tmp/session-summary-${Date.now()}.txt`;
327→    await Bun.write(tmpFile, summarizePrompt);
328→    const proc = Bun.spawn(
329→      ["bash", "-c", `cat "${tmpFile}" | claude -p --model haiku --output-format json`],
330→      {
331→        stdout: "pipe",
332→        stderr: "pipe",
333→        env: { ...process.env, SKIP_SESSION_SUMMARY: "1" },
334→      },
335→    );
336→    const timeoutId = setTimeout(() => proc.kill(), 30000);
337→    const result = { stdout: await new Response(proc.stdout).text() };
338→    clearTimeout(timeoutId);
339→    await Bun.$`rm -f ${tmpFile}`.quiet();
340→
341→    let summary: string;
342→    try {
343→      const summaryOutput = JSON.parse(result.stdout);
344→      summary = summaryOutput.result ?? result.stdout;
345→    } catch {
346→      summary = result.stdout;
347→    }
348→
349→    if (
350→      summary &&
351→      summary.length > 20 &&
352→      !summary.trim().toLowerCase().includes("no significant learnings")
353→    ) {
354→      await fetch(`${config.apiUrl}/api/memory/index`, {
355→        method: "POST",
356→        headers: apiHeaders(config),
357→        body: JSON.stringify({
358→          agentId: config.agentId,
359→          content: summary,
360→          name: taskContext
361→            ? `Session: ${taskContext.slice(0, 80)}`
362→            : `Session: ${new Date().toISOString().slice(0, 16)}`,
363→          scope: "agent",
364→          source: "session_summary",
365→          sourceTaskId: config.taskId,
366→        }),
367→      });
368→    }
369→  } catch {
370→    /* non-blocking */
371→  }
372→}
373→
374→/**
375→ * Create the swarm hooks extension factory for pi-mono.
376→ *
377→ * This maps all agent-swarm hook behaviors to pi-mono extension events
378→ * with full behavioral parity to src/hooks/hook.ts.
379→ */
380→export function createSwarmHooksExtension(config: SwarmHooksConfig): ExtensionFactory {
381→  return (pi) => {
382→    // === session_start → SessionStart ===
383→    pi.on("session_start", async (_event, _ctx) => {
384→      // Ping server
385→      fireAndForget(`${config.apiUrl}/ping`, {
386→        method: "POST",
387→        headers: apiHeaders(config),
388→      });
389→
390→      // Clear stale tool loop history
391→      if (config.taskId) {
392→        await clearToolHistory(config.taskId);
393→      }
394→
395→      // Lead agents: inject concurrent context
396→      if (config.isLead) {
397→        const ctx = await fetchConcurrentContext(config);
398→        if (ctx) {
399→          console.log(ctx);
400→        }
401→      }
402→    });
403→
404→    // === tool_call → PreToolUse ===
405→    pi.on("tool_call", async (event, _ctx) => {
406→      // Workers only: check task cancellation
407→      if (!config.isLead && config.taskId) {
408→        const { cancelled, reason } = await isTaskCancelled(config);
409→        if (cancelled) {
410→          const cancelReason = reason || "Task cancelled by lead or creator";
411→          return {
412→            block: true,
413→            reason:
414→              `🛑 TASK CANCELLED: Your current task (${config.taskId.slice(0, 8)}) has been cancelled. Reason: "${cancelReason}". ` +
415→              `Stop working on this task immediately. Do NOT continue making tool calls. ` +
416→              `Use store-progress to acknowledge the cancellation and mark the task as failed, then wait for new tasks.`,
417→          };
418→        }
419→      }
420→
421→      // Workers only: tool loop detection
422→      if (!config.isLead && config.taskId) {
423→        const toolName = event.toolName;
424→        const toolInput = "input" in event ? (event.input as Record<string, unknown>) : {};
425→
426→        const loopResult = await checkToolLoop(config.taskId, toolName, toolInput);
427→
428→        if (loopResult.blocked) {
429→          return {
430→            block: true,
431→            reason:
432→              `LOOP DETECTED: ${loopResult.reason} ` +
433→              "Stop repeating this action and try a fundamentally different approach. " +
434→              "If you're truly stuck, use store-progress to report the blocker.",
435→          };
436→        }
437→
438→        if (loopResult.severity === "warning" && loopResult.reason) {
439→          console.log(`Warning: ${loopResult.reason}`);
440→        }
441→      }
442→
443→      // Block poll-task when polling limit reached
444→      if (event.toolName?.endsWith("poll-task")) {
445→        const shouldBlock = await checkShouldBlockPolling(config);
446→        if (shouldBlock) {
447→          return {
448→            block: true,
449→            reason:
450→              "🛑 POLLING LIMIT REACHED: You have exceeded the maximum empty poll attempts. " +
451→              "EXIT NOW - do not make any more tool calls.",
452→          };
453→        }
454→      }
455→
456→      // Shared disk write prevention (Archil only — skip in local dev)
457→      if (process.env.ARCHIL_MOUNT_TOKEN) {
458→        // Pi-mono uses lowercase tool names: "write", "edit"
459→        if (event.toolName === "write" || event.toolName === "edit") {
460→          const toolInput =
461→            "input" in event
462→              ? (event.input as { file_path?: string; path?: string } | undefined)
463→              : undefined;
464→          const targetPath = toolInput?.file_path || toolInput?.path || "";
465→          if (
466→            targetPath.startsWith("/workspace/shared/") &&
467→            !isOwnedSharedPath(targetPath, config.agentId)
468→          ) {
469→            console.log(sharedDiskWriteWarning(config.agentId));
470→          }
471→        }
472→      }
473→
474→      return undefined;
475→    });
476→
477→    // === tool_result → PostToolUse ===
478→    pi.on("tool_result", async (event, _ctx) => {
479→      // Heartbeat (workers only, fire-and-forget)
480→      if (!config.isLead && config.taskId) {
481→        fireAndForget(`${config.apiUrl}/api/active-sessions/heartbeat/${config.taskId}`, {
482→          method: "PUT",
483→          headers: apiHeaders(config),
484→        });
485→      }
486→
487→      // Activity timestamp (fire-and-forget)
488→      fireAndForget(`${config.apiUrl}/api/agents/${config.agentId}/activity`, {
489→        method: "PUT",
490→        headers: apiHeaders(config),
491→      });
492→
493→      // Shared disk write failure detection (Archil only — safety net)
494→      if (process.env.ARCHIL_MOUNT_TOKEN) {
495→        // Pi-mono uses lowercase tool names
496→        if (event.toolName === "write" || event.toolName === "edit" || event.toolName === "bash") {
497→          const resultStr = JSON.stringify(event.content ?? []);
498→          if (resultStr.includes("Read-only file system")) {
499→            const resultInput = event.input as { file_path?: string; path?: string } | undefined;
500→            const resultPath = resultInput?.file_path || resultInput?.path || "";
501→            if (
502→              resultPath.startsWith("/workspace/shared/") &&
503→              !isOwnedSharedPath(resultPath, config.agentId)
504→            ) {
505→              console.log(sharedDiskWriteWarning(config.agentId));
506→            } else if (!resultPath) {
507→              // Bash tool — no file_path, just warn generically
508→              console.log(sharedDiskWriteWarning(config.agentId));
509→            }
510→          }
511→        }
512→      }
513→
514→      // File sync: check if tool wrote to identity files or memory dirs
515→      // Pi-mono uses tool names: "write", "edit" (lowercase, unlike Claude's "Write", "Edit")
516→      const toolName = event.toolName;
517→      const input = event.input as { file_path?: string; path?: string } | undefined;
518→      const editedPath = input?.file_path || input?.path;
519→
520→      if ((toolName === "write" || toolName === "edit") && editedPath) {
521→        // Identity files
522→        if (
523→          editedPath === "/workspace/SOUL.md" ||
524→          editedPath === "/workspace/IDENTITY.md" ||
525→          editedPath === "/workspace/TOOLS.md"
526→        ) {
527→          void syncIdentityFilesToServer(config, "self_edit");
528→        }
529→
530→        // Setup script
531→        if (editedPath.startsWith("/workspace/start-up")) {
532→          void syncSetupScriptToServer(config, "self_edit");
533→        }
534→
535→        // Memory auto-index
536→        if (
537→          editedPath.startsWith("/workspace/personal/memory/") ||
538→          editedPath.startsWith("/workspace/shared/memory/")
539→        ) {
540→          void autoIndexMemoryFile(config, editedPath);
541→        }
542→      }
543→
544→      // Reminders
545→      if (config.isLead && event.toolName?.endsWith("send-task")) {
546→        console.log(
547→          "Task sent successfully. Monitor progress using the get-task-details tool periodically.",
548→        );
549→      } else if (!config.isLead) {
550→        console.log(
551→          "Remember to call store-progress periodically to update the lead agent on your progress.",
552→        );
553→      }
554→
555→      return undefined;
556→    });
557→
558→    // === context → PreCompact ===
559→    // The context event allows injecting messages before compaction.
560→    // We log the goal reminder to console (it gets captured in context).
561→    pi.on("context", async (_event, _ctx) => {
562→      if (!config.taskId) return undefined;
563→
564→      try {
565→        const taskDetails = await fetchTaskDetails(config);
566→        if (taskDetails) {
567→          const reminder = [
568→            "=== GOAL REMINDER (injected before context compaction) ===",
569→            `Task ID: ${taskDetails.id}`,
570→            `Task: ${taskDetails.task}`,
571→          ];
572→          if (taskDetails.progress) {
573→            reminder.push(`Current Progress: ${taskDetails.progress}`);
574→          }
575→          reminder.push("=== Continue working on this task after compaction ===");
576→          console.log(reminder.join("\n"));
577→        }
578→      } catch {
579→        /* don't block compaction */
580→      }
581→
582→      return undefined;
583→    });
584→
585→    // === input → UserPromptSubmit ===
586→    pi.on("input", async (_event, _ctx) => {
587→      // Workers only: check task cancellation at start of new iteration
588→      if (!config.isLead && config.taskId) {
589→        const { cancelled, reason } = await isTaskCancelled(config);
590→        if (cancelled) {
591→          const cancelReason = reason || "Task cancelled by lead or creator";
592→          console.log(
593→            `🛑 TASK CANCELLED: ${cancelReason}. Stop working and use store-progress to acknowledge.`,
594→          );
595→          return { action: "handled" as const };
596→        }
597→      }
598→      return undefined;
599→    });
600→
601→    // === session_shutdown → Stop ===
602→    pi.on("session_shutdown", async (_event, ctx) => {
603→      // Sync identity files and setup script
604→      await syncIdentityFilesToServer(config);
605→      await syncSetupScriptToServer(config);
606→
607→      // Session summarization — get session file from context's session manager
608→      const sessionFile = ctx.sessionManager.getSessionFile?.();
609→      if (!process.env.SKIP_SESSION_SUMMARY) {
610→        await summarizeSession(config, sessionFile);
611→      }
612→
613→      // Mark agent offline
614→      fireAndForget(`${config.apiUrl}/close`, {
615→        method: "POST",
616→        headers: apiHeaders(config),
617→      });
618→    });
619→  };
620→}
